const FixedConfirmationToastPositionedExample = () => {
  const [open, setOpen] = useState(true)
  const [vertical, setVertical] = useState('top')
  const [horizontal, setHorizontal] = useState('center')

  return (
    <>
      <Button
          marginRight="xs"
          onClick={() => {
            setVertical('top')
            setHorizontal('center')
            setOpen(true)
          }}
          text="Top Center"
          variant="secondary"
      />
      <Button
          marginRight="xs"
          onClick={() => {
            setVertical('top')
            setHorizontal('right')
            setOpen(true)
          }}
          text="Top Right"
          variant="secondary"
      />
      <Button
          onClick={() => {
            setVertical('bottom')
            setHorizontal('right')
            setOpen(true)
          }}
          text="Bottom Right"
          variant="secondary"
      />
      {{component}}
    </>
  )
}

<FixedConfirmationToastPositionedExample />
